sys_ui_action.script:
(function executeAction(current, previous /*null when async*/) {
    var newRecord = new GlideRecord('x_1839224_chroma_0_chromatech_customer_queries');
    newRecord.initialize();  // Prepares a new empty record

    // Copy the fields you actually want to duplicate
    newRecord.x_requester          = current.requester;
    newRecord.product              = current.product;
    newRecord.description          = current.description;
    newRecord.issue_category       = current.issue_category;
    newRecord.issue_state          = current.issue_state;
    newRecord.short_description    = current.short_description;
    newRecord.approval             = current.approval;          // or current.approval_query ?
    newRecord.x_vip_query          = current.vip_query;
    newRecord.x_contact_type       = current.contact_type;    // or current.contact_type ?
    newRecord.contact_type         = current.contact_type;
    newRecord.assigned_to          = current.assigned_to;
    newRecord.assignment_group     = current.assignment_group;
    newRecord.priority             = current.priority;
    newRecord.email                = current.email;
    newRecord.phone                = current.phone;
    newRecord.place                = current.place;

    // Add any other fields you want to copy here, e.g.:
    // newRecord.some_other_field  = current.some_other_field;

    // Important: Do NOT copy number if it's auto-numbered — let the system generate a new one
    // Do NOT copy sys_id, sys_created_on, sys_updated_on, sys_created_by, etc.

    var newSysId = newRecord.insert();

    if (newSysId) {
        // Redirect to the newly created record
        action.setRedirectURL('x_1839224_chroma_0_chromatech_customer_queries.do?sys_id=' + newSysId);
        // Optional: gs.addInfoMessage('Query copied successfully.');
    } else {
        gs.addErrorMessage('Failed to copy the query. Please check mandatory fields or permissions.');
    }

})(current, previous);
